export type UserRole = 'merchant' | 'customer';

export interface Profile {
  id: string;
  role: UserRole;
  email: string;
  created_at: string;
}

export interface Merchant {
  id: string;
  profile_id: string;
  business_name: string;
  loyalty_type: 'points' | 'stamps' | 'both';
  subscription_status: 'trial' | 'active' | 'cancelled' | 'past_due';
}

export interface Customer {
  id: string;
  profile_id: string;
}

export interface LoyaltyCard {
  id: string;
  customer_id: string;
  merchant_id: string;
  total_points: number;
  total_stamps: number;
  stamps_current_card: number;
}
EOF

