// ============================================================
// AstroLab — Types TypeScript alignes 1:1 avec le schema SQL
// ============================================================

import type {
  UserRole,
  LoyaltyType,
  SubscriptionStatus,
  SubscriptionPlan,
  CampaignType,
  CampaignStatus,
  TargetAudience,
  QRType,
  OfferType,
  RewardType,
  DeviceType,
} from './enums';

// Re-export enum types
export type {
  UserRole,
  LoyaltyType,
  SubscriptionStatus,
  SubscriptionPlan,
  CampaignType,
  CampaignStatus,
  TargetAudience,
  QRType,
  OfferType,
  RewardType,
  DeviceType,
};

// -------------------------------------------------------
// profiles
// -------------------------------------------------------
export interface Profile {
  id: string;
  role: UserRole;
  email: string;
  full_name: string | null;
  avatar_url: string | null;
  created_at: string;
  updated_at: string;
}

// -------------------------------------------------------
// merchants
// -------------------------------------------------------
export interface Merchant {
  id: string;
  profile_id: string;
  business_name: string;
  business_description: string | null;
  business_address: string | null;
  business_phone: string | null;
  business_logo_url: string | null;
  loyalty_type: LoyaltyType;
  points_per_scan: number;
  stamps_per_scan: number;
  stamps_per_card: number;
  subscription_status: SubscriptionStatus;
  subscription_plan: SubscriptionPlan;
