export const USER_ROLES = ['merchant', 'customer'] as const;
export type UserRole = (typeof USER_ROLES)[number];

export const LOYALTY_TYPES = ['points', 'stamps', 'both'] as const;
export type LoyaltyType = (typeof LOYALTY_TYPES)[number];

export const SUBSCRIPTION_STATUSES = ['trial', 'active', 'cancelled', 'past_due'] as const;
export type SubscriptionStatus = (typeof SUBSCRIPTION_STATUSES)[number];

export const SUBSCRIPTION_PLANS = ['starter', 'pro', 'business'] as const;
export type SubscriptionPlan = (typeof SUBSCRIPTION_PLANS)[number];

export const CAMPAIGN_TYPES = ['manual', 'scheduled', 'ai_suggested', 'inactivity_alert', 'welcome'] as const;
export type CampaignType = (typeof CAMPAIGN_TYPES)[number];

export const CAMPAIGN_STATUSES = ['draft', 'scheduled', 'active', 'completed', 'cancelled'] as const;
export type CampaignStatus = (typeof CAMPAIGN_STATUSES)[number];

export const TARGET_AUDIENCES = ['all', 'active', 'inactive', 'new', 'vip'] as const;
export type TargetAudience = (typeof TARGET_AUDIENCES)[number];

export const QR_TYPES = ['counter', 'campaign'] as const;
export type QRType = (typeof QR_TYPES)[number];

export const OFFER_TYPES = ['discount_percent', 'discount_fixed', 'free_item', 'bonus_points', 'bonus_stamps'] as const;
export type OfferType = (typeof OFFER_TYPES)[number];

export const REWARD_TYPES = ['points', 'stamps'] as const;
export type RewardType = (typeof REWARD_TYPES)[number];

export const DEVICE_TYPES = ['web', 'ios', 'android'] as const;
export type DeviceType = (typeof DEVICE_TYPES)[number];

